```json
{
  "global": "Navigate the ServiceNow interface to locate and open the current user's trade offers list.",
  "subtasks": [
    {
      "subtask": "Access the ServiceNow application navigator",
      "atomics": [
        "Click on the 'All' menu or application navigator hamburger icon in the top-left banner",
        "Wait for the navigation panel to expand and become interactive"
      ]
    },
    {
      "subtask": "Locate the trade offers module or menu entry",
      "atomics": [
        "Type 'trade offers' in the application navigator search box",
        "Scan returned module results for a 'Trade Offers' or 'My Trade Offers' entry",
        "Alternatively, browse to the relevant application group (e.g., Procurement or Catalog) to find the trade offers link"
      ]
    },
    {
      "subtask": "Open the trade offers view",
      "atomics": [
        "Click the 'Trade Offers' module link in the navigator results",
        "Confirm the trade offers list or landing page loads in the main content frame"
      ]
    }
  ],
  "global_atomics": [
    "Verify the opened page URL or page title contains 'trade_offer' or equivalent to confirm correct navigation"
  ],
  "gold_actions": {
    "global": "Click the application navigator, search for 'trade offers', and click the resulting module link to open the trade offers list view.",
    "subtasks": [
      {
        "subtask": "Click the application navigator toggle button (hamburger or 'All' label) in the ServiceNow top banner to open the nav panel",
        "atomics": [
          "Click element with aria-label='All' or the hamburger icon in the top-left of the ServiceNow chrome",
          "Assert the left-side navigation drawer is visible and the search field is focused or available"
        ]
      },
      {
        "subtask": "Search and find the Trade Offers module in the navigator",
        "atomics": [
          "Type the string 'trade offers' into the navigator filter/search input field",
          "Read the filtered module list and identify the entry labeled 'Trade Offers' or 'My Trade Offers'",
          "If not found via search, expand the application group 'Procurement' or 'Service Catalog' and scan child menu items for 'Trade Offers'"
        ]
      },
      {
        "subtask": "Click the Trade Offers module link to load the list view",
        "atomics": [
          "Click the 'Trade Offers' anchor element in the navigator results",
          "Wait for the main content iframe to reload and display the trade_offer list table"
        ]
      }
    ],
    "global_atomics": [
      "Assert that the current page title or breadcrumb reads 'Trade Offers' and the list table with offer rows is visible in the main frame"
    ]
  }
}
```
